import { AES } from 'react-native-aes-crypto';
import moment from "moment";
import keys from './config';

const key = keys.defaultKey; // The secret key
const iv  = keys.defaultIV;   // Initial vector for encrypting and decrypting

// Encrypt a string using AES, return it's base64 encoded version
export function encrypt(dataToEncrypt) {
  const encryptedData =  AES.encrypt(dataToEncrypt, key, iv);

  console.log('Encrypted data: ' + JSON.stringify(encryptedData));

  //return base64 version of the data
  let encodedEncryptedData =  window.btoa(JSON.stringify({
    'ciphertext':    encryptedData.ciphertext,
    'encryptionKey': encryptedData.encryptionKey, 
    'initializationVector': encryptedData.initializationVector 
  }));
  return { data: JSON.parse(encodedEncryptedData)};
}

// Decrypt a base64 encoded string using AES and the supplied key/iv, return the original string.
export function decrypt(dataToDecrypt) {
    let decodedEncryptedData =  window.atob(JSON.stringify({
        'ciphertext':    dataToDecrypt['ciphertext'], 
        'encryptionKey': dataToDecrypt['encryptionKey'], 
        'initializationVector': dataToDecrypt['initializationVector']}));
    console.log('Decrypted Data: ' + JSON.stringify(decodedEncryptedData));

    const encryptedData =  AES.decrypt({
        'ciphertext':    decodedEncryptedData,
        'encryptionKey': key, 
        'initializationVector': iv 
    });

    return encryptedData;
}

